describe('User Service (integration)', () => {
  it('creates a user and retrieves it by email', async () => {
    const created = await createUser({
      name: 'Alice',
      email: 'alice@example.com',
      password: 'securePassword123',
    });

    expect(created.id).toBeDefined();
    expect(created.email).toBe('alice@example.com');

    const found = await getUserByEmail('alice@example.com');
    expect(found).not.toBeNull();
    expect(found!.name).toBe('Alice');
  });

  it('hashes the password before storing', async () => {
    const created = await createUser({
      name: 'Bob',
      email: 'bob@example.com',
      password: 'plaintext',
    });

    // The stored password should NOT be plaintext
    const raw = await db.select().from(users).where(
      users.id.equals(created.id)
    );
    expect(raw[0].passwordHash).not.toBe('plaintext');
  });

  it('rejects duplicate emails', async () => {
    await createUser({
      name: 'Alice',
      email: 'alice@example.com',
      password: 'password1',
    });

    await expect(
      createUser({
        name: 'Alice 2',
        email: 'alice@example.com',
        password: 'password2',
      })
    ).rejects.toThrow(/duplicate/i);
  });
});

