describe('POST /api/users', () => {
  it('creates a new user and returns 201', async () => {
    const res = await request(app)
      .post('/api/users')
      .send({ name: 'Alice', email: 'alice@test.com', password: 'secure123' })
      .expect('Content-Type', /json/)
      .expect(201);

    expect(res.body).toMatchObject({
      name: 'Alice',
      email: 'alice@test.com',
    });
    expect(res.body.password).toBeUndefined(); // Never expose passwords
    expect(res.body.id).toBeDefined();
  });

  it('returns 400 for missing required fields', async () => {
    const res = await request(app)
      .post('/api/users')
      .send({ name: 'Alice' }) // Missing email and password
      .expect(400);

    expect(res.body.errors).toBeDefined();
  });

  it('returns 409 for duplicate email', async () => {
    // Create first user
    await request(app)
      .post('/api/users')
      .send({ name: 'Alice', email: 'alice@test.com', password: 'secure123' });

    // Try to create another with the same email
    const res = await request(app)
      .post('/api/users')
      .send({ name: 'Bob', email: 'alice@test.com', password: 'other456' })
      .expect(409);

    expect(res.body.error).toMatch(/already exists/i);
  });
});

