import { render } from '@testing-library/react';
import { performance } from 'perf_hooks';
import DataTable from '../../src/components/DataTable';

// Generate a large dataset
const largeDataset = Array.from({ length: 1000 }, (_, i) => ({
  id: i,
  name: `User ${i}`,
  email: `user${i}@example.com`,
  role: i % 3 === 0 ? 'admin' : 'member',
  createdAt: new Date(2024, 0, i + 1).toISOString(),
}));

describe('DataTable performance', () => {
  it('renders 1000 rows within 200ms', () => {
    const start = performance.now();

    render(
      <DataTable
        data={largeDataset}
        columns={['name', 'email', 'role', 'createdAt']}
      />
    );

    const duration = performance.now() - start;

    // Enforce a performance budget
    expect(duration).toBeLessThan(200);
    console.log(`Rendered 1000 rows in ${duration.toFixed(1)}ms`);
  });

  it('re-renders efficiently when a single row changes', () => {
    const { rerender } = render(
      <DataTable data={largeDataset} columns={['name', 'email']} />
    );

    // Change just one row
    const updatedData = [...largeDataset];
    updatedData[500] = { ...updatedData[500], name: 'Updated User' };

    const start = performance.now();
    rerender(<DataTable data={updatedData} columns={['name', 'email']} />);
    const duration = performance.now() - start;

    // Re-render should be faster than initial render
    expect(duration).toBeLessThan(100);
  });
});

